def global_compiler_lock(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        with _compiler_lock:
            return func(*args, **kwargs)
    return wrapper


def _transform_ir(func_body: ir.Block,
                  bytecode_version: bc.BytecodeVersion,
                  param_constraints: Sequence[tuple[tuple[ir.Var, ...], ParameterConstraint]]):
    eliminate_assign_ops(func_body)
    dead_code_elimination_pass(func_body)
    dataflow_result = dataflow_analysis(func_body, param_constraints)

    if not CUDA_TILE_TESTING_DISABLE_DIV:
        add_divby_pass(func_body, dataflow_result)

    if not CUDA_TILE_TESTING_DISABLE_TOKEN_ORDER:
        token_order_pass(func_body, dataflow_result)

    rewrite_patterns(func_body)

    # Loop invariant code motion needs to run after the token order pass.
    # Otherwise, it may incorrectly hoist load operations out of the loop.
    hoist_loop_invariants(func_body)

    # For version < V_13_3, MakePartitionView must be emitted inline before its consumer.
    # Code motion may hoist it to an outer block; copy it back where needed.
    if bytecode_version < BytecodeVersion.V_13_3:
        unhoist_partition_views(func_body)

    split_loops(func_body)

    pointer, pointer_shape, final_mask, array_dtype = _process_raw_array_memory_pointer_and_mask(
        self, offset, mask)
    return _atomic_rmw_core(int_mode, uint_mode, float_mode, bitwise, supported_dtypes,
                            array_dtype, pointer, pointer_shape, final_mask,
                            update, memory_order, memory_scope)


@dataclass(eq=False)
class MakeToken(Operation, opcode="make_token"):

    @override
    def generate_bytecode(self, ctx: BytecodeContext) -> bc.Value:
        return bc.encode_MakeTokenOp(ctx.builder, ctx.type_table.Token)


def make_token(*, block: Block, res: Var, loc: Loc) -> None:
    make_token_op = MakeToken(result_vars=(res,), loc=loc)
    block.append(make_token_op)


@dataclass(eq=False)
class JoinTokens(Operation, opcode="join_tokens"):
    tokens: Tuple[Var, ...] = operand()

    @override
    def generate_bytecode(self, ctx: BytecodeContext) -> bc.Value:
        tokens = tuple(ctx.get_value(x) for x in self.tokens)
        return bc.encode_JoinTokensOp(ctx.builder, ctx.type_table.Token, tokens)


def join_tokens(tokens: Tuple[Var, ...], *, block: Block, res: Var, loc: Loc) -> None:
    join_tokens_op = JoinTokens(tokens=tokens, result_vars=(res,), loc=loc)
    block.append(join_tokens_op)


