def _invert(x: int | bool, bool_action: Literal['raise'] | Literal['not']):
    if isinstance(x, bool):
        if bool_action == 'not':
            return not x
        else:
            assert bool_action == 'raise'
            raise TileTypeError(
                '`~` on boolean constant is not supported, please use ct.bitwise_not')
    return ~x


